+pub struct ReplayMinimizationEvidence {
+    /// Snapshot from the original replay/failure evidence.
+    pub before: ReplayFailureSnapshot,
+    /// Snapshot after reduction/minimization.
+    pub after: ReplayFailureSnapshot,
