+const BEAD_ID: &str = "bd-mblr.5.4.1";
+const SEED: u64 = 20260213;
+
+#[derive(Debug, Clone, PartialEq, Eq, PartialOrd, Ord)]
+struct ContractViolation {
+    path: String,
+    message: String,
+}
+
+fn run_context(run_id: &str) -> RunContext {
+    RunContext::new(
+        run_id,
+        BEAD_ID,
+        Some("INFRA-6"),
+        Some(SEED),
+        Some("fsqlite"),
